#include <vector>
#include <queue>
#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    unordered_map<long long, vector<pair<long long, pair<long long, long long>>>> adj;
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long start = edge[2];
        long long end = edge[3];
        adj[u].emplace_back(v, make_pair(start, end));
    }

    // Dijkstra's algorithm with priority queue
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, -1);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        long long time = pq.top().first;
        long long node = pq.top().second;
        pq.pop();

        if (node == n - 1) {
            return time;
        }

        if (dist[node] != time) continue;

        // Try to stay at the current node
        if (dist[node] != -1) {
            if (dist[node] + 1 < dist[n - 1]) {
                dist[n - 1] = dist[node] + 1;
                pq.push({dist[node] + 1, n - 1});
