            if (start <= time && time <= end) {
                long long new_time = time + 1;
                if (dist[v] == -1 || new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.push({new_time, v});
                }
            }
        }
    }

    return -1;
}

