import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        // Build adjacency list
        Map<Long, List<AbstractMap.SimpleEntry<Long, AbstractMap.SimpleEntry<Long, Long>>>> adj = new HashMap<>();
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long start = edge[2];
            long end = edge[3];
            adj.putIfAbsent(u, new ArrayList<>());
            adj.get(u).add(new AbstractMap.SimpleEntry<>(v, new AbstractMap.SimpleEntry<>(start, end)));
